            } else {
                statusTextView.text = "Received shared text"
                Log.i(TAG, "Shared text received: $sharedText")
            }

            if (sharedSubject != null) {
                val subjectLabel = TextView(this).apply {
                    text = "Subject:"
                    textSize = 14f
