                        600
                    ).apply {
                        topMargin = 8
                        bottomMargin = 16
                    }
                    scaleType = ImageView.ScaleType.FIT_CENTER
                    adjustViewBounds = true
                }

                try {
                    imageView.setImageURI(uri)
                    contentContainer.addView(imageView)
                } catch (e: Exception) {
                    Log.e(TAG, "Error loading image $index: ${e.message}")
                    val errorText = TextView(this).apply {
                        text = "Error loading image ${index + 1}: ${e.message}"
                        textSize = 14f
                        setPadding(0, 4, 0, 8)
                    }
                    contentContainer.addView(errorText)
                }

                processSharedImage(uri)
            }
        } else {
            statusTextView.text = "No images found in shared content."
            Log.w(TAG, "Received SEND_MULTIPLE intent but EXTRA_STREAM was null or empty")
        }
    }

